import { Component, OnInit } from '@angular/core';
import { DataService } from 'src/app/services/data.service';
import { NotificationService } from 'src/app/services/notification.service';

@Component({
  selector: 'app-sibling',
  templateUrl: './sibling.component.html',
  styleUrls: ['./sibling.component.scss']
})
export class SiblingComponent implements OnInit {
  message : string = '';
  newMessage : string ='';

  constructor(private dataService : DataService,  private notificationService: NotificationService){}

  ngOnInit(): void {
    // subscrive to our data;
    //service
    this.dataService.currentMessage.subscribe(message => {
      this.message = message
    })
  }


  updateMessage(){
    if(this.newMessage){
      this.dataService.updateMessage(this.newMessage);
      this.n
      this.newMessage = '';
    }
  }

  notifyUpdate(): void {
    this.notificationService.info('Message updated from sibling component');
  }



}
<div class="sibling-container" >
  <h2>Sibling compoinent</h2>
  <input type="text" [(ngModel)]="newMessage" >
  <button (click)="updateMessage()">Update shared message</button>
  <button (click)="notifyUpdate()">Notify Update</button>
</div>
